param([string]$VencordPath = "$env:USERPROFILE\Downloads\VN\Vencord")
$ModalPath = Join-Path $VencordPath "src\components\settings\tabs\plugins\PluginModal.tsx"
if (!(Test-Path $ModalPath)) { throw "PluginModal.tsx not found: $ModalPath" }
$Text = Get-Content $ModalPath -Raw
$Original = @'
{!pluginMeta.userPlugin && (
                        <div className="vc-settings-modal-links">
                            <WebsiteButton
                                text="View more info"
                                href={`https://vencord.dev/plugins/${plugin.name}`}
                            />
                            <GithubButton
                                text="View source code"
                                href={`https://github.com/${gitRemote}/tree/main/src/plugins/${pluginMeta.folderName}`}
                            />
                        </div>
                    )}
'@
$Replacement = @'
{plugin.name === "TikTokRPC" ? (
                        <div className="vc-settings-modal-links">
                            <Tooltip text="TikTok">
                                {props => (
                                    <a {...props} href="https://www.tiktok.com/@boykisseraf" target="_blank" rel="noreferrer">
                                        <svg width="32" height="32" viewBox="0 0 32 32" aria-hidden="true" className="vc-settings-modal-link-icon">
                                            <circle cx="16" cy="16" r="14.5" fill="#111214" />
                                            <image href="data:image/svg+xml;base64," x="2.8" y="5.2" width="21.5" height="21.5" preserveAspectRatio="xMidYMid meet" />
                                        </svg>
                                    </a>
                                )}
                            </Tooltip>
                            <Tooltip text="guns.lol">
                                {props => (
                                    <a {...props} href="https://guns.lol/boykisseraf" target="_blank" rel="noreferrer">
                                        <svg width="32" height="32" viewBox="0 0 32 32" aria-hidden="true" className="vc-settings-modal-link-icon">
                                            <circle cx="16" cy="16" r="14.5" fill="#111214" />
                                            <image href="data:image/webp;base64," x="5.2" y="5.3" width="20.7" height="20.7" preserveAspectRatio="xMidYMid meet" />
                                        </svg>
                                    </a>
                                )}
                            </Tooltip>
                        </div>
                    ) : !pluginMeta.userPlugin && (
                        <div className="vc-settings-modal-links">
                            <WebsiteButton
                                text="View more info"
                                href={`https://vencord.dev/plugins/${plugin.name}`}
                            />
                            <GithubButton
                                text="View source code"
                                href={`https://github.com/${gitRemote}/tree/main/src/plugins/${pluginMeta.folderName}`}
                            />
                        </div>
                    )}
'@
$OldPattern = '(?s)\{plugin\.name === "TikTokRPC" \? \(\s*<div className="vc-settings-modal-links">.*?</div>\s*\) : !pluginMeta\.userPlugin && \('
$ReplacementPrefix = @'
{plugin.name === "TikTokRPC" ? (
                        <div className="vc-settings-modal-links">
                            <Tooltip text="TikTok">
                                {props => (
                                    <a {...props} href="https://www.tiktok.com/@boykisseraf" target="_blank" rel="noreferrer">
                                        <svg width="32" height="32" viewBox="0 0 32 32" aria-hidden="true" className="vc-settings-modal-link-icon">
                                            <circle cx="16" cy="16" r="14.5" fill="#111214" />
                                            <image href="data:image/svg+xml;base64," x="2.8" y="5.2" width="21.5" height="21.5" preserveAspectRatio="xMidYMid meet" />
                                        </svg>
                                    </a>
                                )}
                            </Tooltip>
                            <Tooltip text="guns.lol">
                                {props => (
                                    <a {...props} href="https://guns.lol/boykisseraf" target="_blank" rel="noreferrer">
                                        <svg width="32" height="32" viewBox="0 0 32 32" aria-hidden="true" className="vc-settings-modal-link-icon">
                                            <circle cx="16" cy="16" r="14.5" fill="#111214" />
                                            <image href="data:image/webp;base64," x="5.2" y="5.3" width="20.7" height="20.7" preserveAspectRatio="xMidYMid meet" />
                                        </svg>
                                    </a>
                                )}
                            </Tooltip>
                        </div>
                    ) : !pluginMeta.userPlugin && (
'@
if ($Text -match $OldPattern) {
    $Text = [regex]::Replace($Text, $OldPattern, $ReplacementPrefix, 1)
    Set-Content $ModalPath $Text -Encoding UTF8
} elseif ($Text.Contains($Original)) {
    $Text = $Text.Replace($Original, $Replacement)
    Set-Content $ModalPath $Text -Encoding UTF8
} else {
    throw "Could not patch PluginModal links block"
}
Write-Host "PluginModal patched"
